{"name": "answer", "arguments": {"kg": "wikidata", "sparql": "PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?countyLabel WHERE {
  ?city rdfs:label "Wake Forest"@en .
  ?city wdt:P17 wd:Q30 .
  ?city wdt:P131 ?county .
  ?county rdfs:label ?countyLabel .
  FILTER (LANG(?countyLabel) = "en")
}", "answer": "Wake Forest is located in Wake County, North Carolina."}}

